// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES - DEMANDES D'AUGMENTATION DE SALAIRE
// Niveaux : PDG / SUPERIEUR / SALARIE / FARHAT / DGA
// DGA = notifié quand jours_restants > 8 ET <= delai_total / 2
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION - DEMANDES AUGMENTATION (avec DGA)');
console.log('═══════════════════════════════════════════════════');
console.log(`Demandes reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const data = item.json;

  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  if (data.niveau_escalade === 'PDG') {
    destinatairePrincipal = {
      code: data.code_pdg,
      nom: data.nom_pdg,
      prenom: data.prenom_pdg,
      email: data.email_pdg,
      telephone: data.telephone_pdg,
      chat_id: data.chat_id_pdg,
      langue: data.langue_pdg || 'FRA',
      bot: data.bot_pdg
    };
    codeDestinataire = data.code_pdg;
    typeDestinataire = 'PDG';

  } else if (data.niveau_escalade === 'SUPERIEUR') {
    destinatairePrincipal = {
      code: data.code_sup,
      nom: data.nom_superieur,
      prenom: data.prenom_superieur,
      email: data.email_superieur,
      telephone: data.num_telephone_sup,
      chat_id: data.chat_id_superieur,
      langue: data.langue_superieur || 'FRA',
      bot: data.bot_superieur
    };
    codeDestinataire = data.code_sup;
    typeDestinataire = 'SUPERIEUR';

  } else if (data.niveau_escalade === 'SALARIE') {
    destinatairePrincipal = {
      code: data.code_salarie,
      nom: data.nom_salarie,
      prenom: data.prenom_salarie,
      email: data.email_salarie,
      telephone: data.num_telephone_salarie,
      chat_id: data.chat_id_salarie,
      langue: data.langue_salarie || 'FRA',
      bot: data.bot_salarie
    };
    codeDestinataire = data.code_salarie;
    typeDestinataire = 'SALARIE';

  } else if (data.niveau_escalade === 'FARHAT') {
    destinatairePrincipal = {
      code: data.code_farhat,
      nom: data.nom_farhat,
      prenom: data.prenom_farhat,
      email: data.email_farhat || null,
      telephone: data.telephone_farhat || null,
      chat_id: data.chat_id_farhat || null,
      langue: data.langue_farhat || 'FRA',
      bot: data.bot_farhat || null
    };
    codeDestinataire = data.code_farhat;
    typeDestinataire = 'FARHAT';

  } else if (data.niveau_escalade === 'DGA') {
    // ─── DGA : email uniquement, pas de Telegram ───
    destinatairePrincipal = {
      code: data.code_dga,
      nom: data.nom_dga,
      prenom: data.prenom_dga,
      email: data.email_dga || null,
      telephone: data.telephone_dga || null,
      chat_id: null,
      langue: data.langue_dga || 'FRA',
      bot: null
    };
    codeDestinataire = data.code_dga;
    typeDestinataire = 'DGA';

  } else {
    console.log(`⏭️  Demande ${data.numero_demande} ignorée (niveau: ${data.niveau_escalade})`);
    return;
  }

  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: typeDestinataire,
      niveau_escalade: data.niveau_escalade,

      salarie: {
        code: data.code_salarie,
        nom: data.nom_salarie,
        prenom: data.prenom_salarie,
        email: data.email_salarie,
        telephone: data.num_telephone_salarie,
        chat_id: data.chat_id_salarie,
        langue: data.langue_salarie || 'FRA',
        bot: data.bot_salarie
      },

      superieur: {
        code: data.code_sup,
        nom: data.nom_superieur,
        prenom: data.prenom_superieur,
        email: data.email_superieur,
        telephone: data.num_telephone_sup,
        chat_id: data.chat_id_superieur,
        langue: data.langue_superieur || 'FRA',
        bot: data.bot_superieur
      },

      pdg: {
        code: data.code_pdg,
        nom: data.nom_pdg,
        prenom: data.prenom_pdg,
        email: data.email_pdg,
        telephone: data.telephone_pdg,
        chat_id: data.chat_id_pdg,
        langue: data.langue_pdg || 'FRA',
        bot: data.bot_pdg
      },

      dga: {
        code: data.code_dga,
        nom: data.nom_dga,
        prenom: data.prenom_dga,
        email: data.email_dga,
        telephone: data.telephone_dga,
        chat_id: null,
        langue: data.langue_dga || 'FRA',
        bot: null
      },

      farhat: {
        code: data.code_farhat,
        nom: data.nom_farhat,
        prenom: data.prenom_farhat,
        email: data.email_farhat,
        telephone: data.telephone_farhat,
        chat_id: data.chat_id_farhat,
        langue: data.langue_farhat || 'FRA',
        bot: data.bot_farhat
      },

      demandes: []
    };
  }

  notifications[cleDestinataire].demandes.push({
    numero_demande: data.numero_demande,
    date_creation_demande: data.date_creation_demande,
    date_controle: data.date_controle,
    utilisateur_createur: data.utilisateur_createur,
    delai_total_jours: data.delai_total_jours,
    date_limite: data.date_limite,
    jours_depuis_creation: data.jours_depuis_creation,
    jours_restants: data.jours_restants,
    salarie_concerne: {
      code: data.code_salarie,
      nom: data.nom_salarie,
      prenom: data.prenom_salarie,
      email: data.email_salarie,
      telephone: data.num_telephone_salarie
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const totalDemandes = notif.demandes.length;
  const joursMin = Math.min(...notif.demandes.map(a => a.jours_restants));
  const joursMax = Math.max(...notif.demandes.map(a => a.jours_restants));
  const delaiTotal = parseInt(notif.demandes[0]?.delai_total_jours) || 10;

  let emailCC = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur.email) emailCC.push(notif.superieur.email);
    if (notif.salarie.email && notif.salarie.chat_id) emailCC.push(notif.salarie.email);
    if (notif.superieur.chat_id) chatIDsCC.push({
      chat_id: notif.superieur.chat_id, bot: notif.superieur.bot,
      langue: notif.superieur.langue, nom: `${notif.superieur.prenom} ${notif.superieur.nom}`
    });
    if (notif.salarie.chat_id) chatIDsCC.push({
      chat_id: notif.salarie.chat_id, bot: notif.salarie.bot,
      langue: notif.salarie.langue, nom: `${notif.salarie.prenom} ${notif.salarie.nom}`
    });

  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.salarie.email && notif.salarie.chat_id) emailCC.push(notif.salarie.email);
    if (notif.salarie.chat_id) chatIDsCC.push({
      chat_id: notif.salarie.chat_id, bot: notif.salarie.bot,
      langue: notif.salarie.langue, nom: `${notif.salarie.prenom} ${notif.salarie.nom}`
    });

  } else if (notif.type_destinataire === 'DGA') {
    // DGA → email uniquement, pas de CC, pas de Telegram

  } else if (notif.type_destinataire === 'FARHAT') {
    // FARHAT → pas de CC
  }
  // SALARIE → pas de CC

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire: notif.type_destinataire,
    niveau_escalade: notif.niveau_escalade,
    email_cc: emailCC.length > 0 ? emailCC.join(',') : null,
    telegram_cc: chatIDsCC.length > 0 ? chatIDsCC : null,
    salarie: notif.salarie,
    superieur: notif.superieur,
    pdg: notif.pdg,
    dga: notif.dga,
    farhat: notif.farhat,
    attestations: notif.demandes,
    statistiques: {
      total_attestations: totalDemandes,
      jours_min: joursMin,
      jours_max: joursMax,
      priorite: notif.niveau_escalade,
      delai_total: delaiTotal,
      seuil_dga: Math.floor(delaiTotal / 2)
    },
    meta: {
      date_traitement: new Date().toISOString(),
      langue_message: notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email: !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\n✅ Notifications structurées: ${resultats.length}`);
console.log('Par type:');
console.log(`  - PDG:       ${resultats.filter(r => r.type_destinataire === 'PDG').length}`);
console.log(`  - Supérieur: ${resultats.filter(r => r.type_destinataire === 'SUPERIEUR').length}`);
console.log(`  - Salarié:   ${resultats.filter(r => r.type_destinataire === 'SALARIE').length}`);
console.log(`  - DGA:       ${resultats.filter(r => r.type_destinataire === 'DGA').length}`);
console.log(`  - Farhat:    ${resultats.filter(r => r.type_destinataire === 'FARHAT').length}`);
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

