function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch(e) { return dateStr; }
}

function formaterDateHeure(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleString(locale, { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  } catch(e) { return dateStr; }
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours === 3) return '🟠';
  if (jours === 4) return '🟡';
  if (jours <= 8) return '🔵';
  return '🟢';
}

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const destinataire = data.destinataire_principal;
  const stats = data.statistiques;
  const attestations = data.attestations;

  let emailSubject = T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE;
  emailSubject += ` - ${stats.total_attestations} demande(s)`;

  let emailBody = `${T.salutation} ${destinataire.prenom} ${destinataire.nom},\n\n`;
  emailBody += `${T.introduction[data.type_destinataire]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_attestations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n`;

  if (data.type_destinataire === 'DGA') {
    emailBody += `${T.seuil_dga}: ${stats.seuil_dga} ${T.jours}\n`;
  }

  if (data.type_destinataire !== 'SALARIE' && data.type_destinataire !== 'DGA') {
    emailBody += `\n${T.salarie_concerne}: ${data.salarie.prenom} ${data.salarie.nom} (${data.salarie.code})\n`;
  }

  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_attestations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  attestations.forEach((att, index) => {
    emailBody += `${index + 1}. ${getEmoji(att.jours_restants)} ${att.numero_demande}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(att.date_creation_demande, langue)}\n`;
    emailBody += `   🧑 ${T.salarie_concerne}: ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom} (${att.salarie_concerne.code})\n`;
    emailBody += `   ⏰ ${T.delai}: ${att.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(att.date_limite, langue)})\n`;
    if (att.jours_restants <= 2) emailBody += `   🚨 ${T.urgent}\n`;
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    emailBody += `🚨 ${T.action_requise}: ${T.urgent}\n`;
  } else if (data.type_destinataire === 'DGA') {
    emailBody += `📌 ${T.instruction_dga}\n`;
  } else {
    emailBody += `📌 ${T.instruction}\n`;
  }
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   ${data.superieur.prenom} ${data.superieur.nom}\n`;
