    message_envoye_a = `${T.cc_message.le_dga} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
    message_envoye_a_email = `${T.cc_message.le_dga} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
  } else if (typeDestinatairePrincipal === 'FARHAT') {
    message_envoye_a = `${T.cc_message.le_farhat} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
    message_envoye_a_email = `${T.cc_message.le_farhat} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
  }

  let emailSubject = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_attestations} demande(s)`;

  let emailBody = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${message_envoye_a_email}.\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_attestations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_attestations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  attestations.forEach((att, index) => {
    emailBody += `${index + 1}. ${getEmoji(att.jours_restants)} ${att.numero_demande}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(att.date_creation_demande, langue)}\n`;
    emailBody += `   🧑 ${T.salarie_concerne}: ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom} (${att.salarie_concerne.code})\n`;
    emailBody += `   ⏰ ${T.delai}: ${att.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(att.date_limite, langue)})\n`;
    if (att.jours_restants <= 2) emailBody += `   🚨 ${T.urgent}\n`;
    emailBody += `\n`;
  });
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `${T.cc_message.action}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   Email: ${data.superieur.email}\n`;
    emailBody += `   Tel: ${data.superieur.telephone || 'N/A'}\n`;
  }
  emailBody += `\n${T.cordialement},\n\n${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  emailBody += `📋 ${T.copie_info}\n${T.ne_pas_repondre}\n`;

  let telegramMessage = `${T.copie_info}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  telegramMessage += `${T.cc_message.base} ${message_envoye_a}.\n\n`;
  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_attestations}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  attestations.slice(0, 3).forEach((att, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(att.jours_restants)} *${att.numero_demande}*\n`;
    telegramMessage += `   📅 ${formaterDate(att.date_creation_demande, langue)}\n`;
    telegramMessage += `   🧑 ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom}\n`;
    telegramMessage += `   ⏰ ${att.jours_restants} ${T.jours} ${T.restant}\n\n`;
