  telegramMessage += `${T.cc_message.action}\n\n`;

  return {
    email: { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  results.push({
    json: {
      ...data,
      messages: messagesPrincipal,
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, langue_utilisee: data.meta.langue_message || 'FRA', date_generation: new Date().toISOString() }
    }
  });

  if (data.type_destinataire === 'SUPERIEUR') {
    if (data.salarie && data.salarie.chat_id) {
      const messagesCC = genererMessageCC(data, data.salarie, 'SUPERIEUR');
      results.push({ json: { ...data, messages: messagesCC, type_envoi: 'CC', destinataire_final: data.salarie, meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
  } else if (data.type_destinataire === 'PDG') {
    if (data.superieur && data.superieur.chat_id) {
      const mCC = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: { ...data, messages: mCC, type_envoi: 'CC', destinataire_final: data.superieur, meta: { ...data.meta, langue_utilisee: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
    if (data.salarie && data.salarie.chat_id) {
      const mCC = genererMessageCC(data, data.salarie, 'PDG');
      results.push({ json: { ...data, messages: mCC, type_envoi: 'CC', destinataire_final: data.salarie, meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
  } else if (data.type_destinataire === 'DGA') {
    // DGA → email uniquement, pas de CC
  } else if (data.type_destinataire === 'FARHAT') {
    if (data.salarie && data.salarie.chat_id) {
      const mCC = genererMessageCC(data, data.salarie, 'FARHAT');
      results.push({ json: { ...data, messages: mCC, type_envoi: 'CC', destinataire_final: data.salarie, meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
  }
});

console.log(`Total messages générés: ${results.length}`);
return results;
